3815	\begin{lemma}\leanok
3816	[Flatness over the base is stable under base change]
3817	  \label{lem:coherent_flat_base_change}
3818	  \lean{AlgebraicGeometry.Scheme.CoherentSheafFlat.of_isPullback}
3819	  \uses{def:coherent_sheaf_flat}
3820	  \source{nitsure-hilbert-quot}
3821	  \textit{Source: [Nitsure], \S 1 (FGA Explained Ch.~5); Stacks 01U9.}
3822	  Let
3823	  \[
3824	    \begin{array}{ccc}
3825	      X' & \xrightarrow{\ g'\ } & X \\
3826	      \downarrow f' & & \downarrow f \\
3827	      S' & \xrightarrow{\ g\ } & S
3828	    \end{array}
3829	  \]
3830	  be a cartesian square of schemes and \(\mathcal{F}\) a quasi-coherent sheaf
3831	  of \(\mathcal{O}_X\)-modules that is flat over \(S\) in the sense of
3832	  \cref{def:coherent_sheaf_flat}.  Then \(g'^* \mathcal{F}\) is flat over
3833	  \(S'\).
3834	\end{lemma}
3835	\begin{proof}
3836	  For a quasi-coherent module, flatness over the base in the sense of
3837	  \cref{def:coherent_sheaf_flat} amounts to flatness of every stalk
3838	  \(\mathcal{F}_x\) over the local ring \(\mathcal{O}_{S, f(x)}\): a module
3839	  over a ring \(B\) with an action of \(A\) through \(A \to B\) is flat over
3840	  \(A\) if and only if all its localizations at primes of \(B\) are flat over
3841	  the corresponding localizations of \(A\).  The stalk of \(g'^*\mathcal{F}\)
3842	  at \(x' \in X'\) is
3843	  \(\mathcal{F}_{g'(x')} \otimes_{\mathcal{O}_{X, g'(x')}}
3844	  \mathcal{O}_{X', x'}\), and since the square is cartesian
3845	  \(\mathcal{O}_{X', x'}\) is a localization of
3846	  \(\mathcal{O}_{X, g'(x')} \otimes_{\mathcal{O}_{S, s}}
3847	  \mathcal{O}_{S', s'}\) (where \(s = f(g'(x'))\), \(s' = f'(x')\)).  Hence
3848	  \((g'^*\mathcal{F})_{x'}\) is a localization of
3849	  \(\mathcal{F}_{g'(x')} \otimes_{\mathcal{O}_{S,s}} \mathcal{O}_{S', s'}\);
3850	  flatness over \(\mathcal{O}_{S,s}\) base-changes to flatness over
3851	  \(\mathcal{O}_{S', s'}\) and is preserved by localization.
3852	\end{proof}
