3854	\begin{lemma}\leanok
3855	[Proper support is stable under base change]
3856	  \label{lem:proper_support_base_change}
3857	  \lean{AlgebraicGeometry.Scheme.Modules.HasProperSupport.of_isPullback}
3858	  \uses{def:has_proper_support, def:modules_annihilator}
3859	  \source{nitsure-hilbert-quot}
3860	  \textit{Source: [Nitsure], \S 1 (FGA Explained Ch.~5); Stacks 01W4, 056H.}
3861	  In the cartesian square of \cref{lem:coherent_flat_base_change}, let
3862	  \(\mathcal{F}\) be a finitely presented sheaf of
3863	  \(\mathcal{O}_X\)-modules whose schematic support is proper over \(S\)
3864	  (\cref{def:has_proper_support}).  Then the schematic support of
3865	  \(g'^* \mathcal{F}\) is proper over \(S'\).
3866	\end{lemma}
3867	\begin{proof}
3868	  \uses{lem:pullback_finite_presentation, lem:isProper_mathlib}
3869	  A local section of \(\mathrm{Ann}(\mathcal{F})\) pulls back to a section
3870	  annihilating \(g'^* \mathcal{F}\), so the pullback ideal
3871	  \(\mathrm{Ann}(\mathcal{F}) \cdot \mathcal{O}_{X'}\) is contained in
3872	  \(\mathrm{Ann}(g'^*\mathcal{F})\) (\cref{def:modules_annihilator}).
3873	  Consequently the schematic support of \(g'^* \mathcal{F}\) is a closed
3874	  subscheme of the base change
3875	  \(Z' := Z \times_X X' = Z \times_S S'\) of the schematic support
3876	  \(Z\) of \(\mathcal{F}\).  Since \(Z \to S\) is proper and properness is
3877	  stable under base change, \(Z' \to S'\) is proper; a closed immersion
3878	  followed by a proper morphism is proper, so the schematic support of
3879	  \(g'^* \mathcal{F}\) is proper over \(S'\).
3880	\end{proof}
